async function seedProducts() {
  console.log(`Seeding ${products.length} products...`);

  for (const p of products) {
    const { data: existing } = await supabase
      .from('products')
      .select('id')
      .eq('sku', p.sku)
      .single();

    if (existing) {
      console.log(`  Skipping ${p.sku} - ${p.name_ar} (exists)`);
      continue;
    }

    const { error } = await supabase.from('products').insert({
      sku: p.sku,
      barcode: `622${Math.floor(100000000000 + Math.random() * 900000000000)}`,
      name_ar: p.name_ar,
      name_en: p.name_ar,
      unit: p.unit,
      unit_price: p.selling_price,
      cost_price: p.cost_price,
      sale_price: p.selling_price,
      current_stock: 50,
      is_active: true,
      description: p.description,
    });

    if (error) {
      console.error(`  ERROR inserting ${p.sku}: ${error.message}`);
    } else {
      console.log(`  ✓ ${p.sku} - ${p.name_ar}`);
    }
  }

  console.log('\nDone!');
}

seedProducts();
